import org.apache.spark.sql._
import org.apache.spark.sql.functions._
import org.apache.spark.sql.expressions.UserDefinedFunction
import org.apache.spark.sql.types._
import javax.servlet.http.{HttpServlet, HttpServletRequest, HttpServletResponse}
import scala.collection.JavaConverters._

class SparkSQLAPI extends HttpServlet {
  val spark = SparkSession.builder()
    .appName("Spark SQL API")
    .master("local[*]")
    .getOrCreate()

  override def doPost(req: HttpServletRequest, resp: HttpServletResponse) {
    req.setCharacterEncoding("UTF-8")
    resp.setContentType("application/json; charset=utf-8")

    val userQuery = req.getParameter("query")
    if (userQuery == null || userQuery.isEmpty) {
      resp.sendError(HttpServletResponse.SC_BAD_REQUEST, "Missing query parameter.")
      return
    }

    try {
      val dataFrame = spark.sql(userQuery)
      val result = dataFrame.collect().map(_.mkString(",")).mkString("[", ",", "]")
      resp.getWriter().write(result)
    } catch {
      case e: Exception =>
        resp.sendError(HttpServletResponse.SC_INTERNAL_SERVER_ERROR, s"Error executing query: ${e.getMessage}")
    } finally {
      spark.stop()
    }
  }
}